changeSet.createView:
SELECT ag.CODE_AGENCE, ag.NOMAGENCE AS nom_agence,
/* ── Encours ─────────────────────────────────────────────── */ COALESCE(enc.encours_brut, 0) AS encours_brut, COALESCE(enc.encours_net, 0) AS encours_net, COALESCE(enc.nb_credits_actifs, 0) AS nb_credits_actifs,
/* ── PAR 30 : crédits avec retard > 30 jours ────────────── */ COALESCE(par30.capital_risque_30, 0) AS capital_risque_par30, CASE WHEN COALESCE(enc.encours_brut, 0) > 0 THEN CAST(COALESCE(par30.capital_risque_30, 0) AS FLOAT) / CAST(enc.encours_brut AS FLOAT) ELSE 0 END AS taux_par_30,
/* ── PAR 90 : crédits avec retard > 90 jours ────────────── */ COALESCE(par90.capital_risque_90, 0) AS capital_risque_par90, CASE WHEN COALESCE(enc.encours_brut, 0) > 0 THEN CAST(COALESCE(par90.capital_risque_90, 0) AS FLOAT) / CAST(enc.encours_brut AS FLOAT) ELSE 0 END AS taux_par_90,
/* ── Arriérés totaux ─────────────────────────────────────── */ COALESCE(par30.total_arrieres, 0) AS total_arrieres, CASE WHEN COALESCE(enc.encours_brut, 0) > 0 THEN CAST(COALESCE(par30.total_arrieres, 0) AS FLOAT) / CAST(enc.encours_brut AS FLOAT) ELSE 0 END AS taux_portefeuille_risque,
/* ── Taux de remboursement ───────────────────────────────── */ COALESCE(remb.total_rembourse, 0) AS total_rembourse, COALESCE(amort.total_echu, 0) AS total_echu, CASE WHEN COALESCE(amort.total_echu, 0) > 0 THEN CAST(COALESCE(remb.total_rembourse, 0) AS FLOAT) / CAST(amort.total_echu AS FLOAT) ELSE 0 END AS taux_remboursement,
/* ── Ratio couverture garanties ──────────────────────────── */ COALESCE(gar.total_garanties, 0) AS total_garanties, CASE WHEN COALESCE(enc.encours_net, 0) > 0 THEN CAST(COALESCE(gar.total_garanties, 0) AS FLOAT) / CAST(enc.encours_net AS FLOAT) ELSE 0 END AS ratio_couverture_garanties
FROM AGENCE ag
/* ── Encours actifs ───────────────────────────────────────────── */ LEFT JOIN ( SELECT c.agence, COUNT(*) AS nb_credits_actifs, SUM(c.MONTANT_DEBLOQUER) AS encours_brut, SUM(c.SOLDE_CAPITAL) AS encours_net FROM Credits c WHERE c.STATUT = 'DEBLOQUE' GROUP BY c.agence ) enc ON enc.agence = ag.CODE_AGENCE
/* ── PAR 30+ (retard > 30 jours) ─────────────────────────────── */ LEFT JOIN ( SELECT p.CODE_AGENCE, SUM(p.SOLDE_CAPITAL) AS capital_risque_30, SUM(p.total_arrieres) AS total_arrieres FROM vue_par_bcm p WHERE p.categorie_par IN ('PAR30','PAR90','PAR180','PAR180_PLUS') GROUP BY p.CODE_AGENCE ) par30 ON par30.CODE_AGENCE = ag.CODE_AGENCE
/* ── PAR 90+ (retard > 90 jours) ─────────────────────────────── */ LEFT JOIN ( SELECT p.CODE_AGENCE, SUM(p.SOLDE_CAPITAL) AS capital_risque_90 FROM vue_par_bcm p WHERE p.categorie_par IN ('PAR90','PAR180','PAR180_PLUS') GROUP BY p.CODE_AGENCE ) par90 ON par90.CODE_AGENCE = ag.CODE_AGENCE
/* ── Remboursements validés ────────────────────────────────────── */ LEFT JOIN ( SELECT r.agence, SUM(r.MONTANT_TOTAL) AS total_rembourse FROM Reglement r WHERE r.STATUT = 'VALIDE' GROUP BY r.agence ) remb ON remb.agence = ag.CODE_AGENCE
/* ── Échéances échues (base de calcul du taux de remboursement) ─ */ LEFT JOIN ( SELECT c2.agence, SUM(a.TOTAL_ECHEANCE) AS total_echu FROM Amortp a JOIN Credits c2 ON c2.IDCREDIT = a.idcredit WHERE a.STATUT_ECHEANCE IN ('EN_RETARD','PARTIELLEMENT_REGLE','REGLE') GROUP BY c2.agence ) amort ON amort.agence = ag.CODE_AGENCE
/* ── Garanties actives ────────────────────────────────────────── */ LEFT JOIN ( SELECT c3.agence, SUM(g.valeur_estimee) AS total_garanties FROM vue_garanties_unifiee g JOIN Credits c3 ON c3.IDCREDIT = g.idcredit WHERE COALESCE(g.statut, 'ACTIF') = 'ACTIF' GROUP BY c3.agence ) gar ON gar.agence = ag.CODE_AGENCE
WHERE ag.ACTIF = 1
